def exact_match(output: str, expected: str) -> bool:
    return output.strip() == expected.strip()

def exact_match_score(output: str, expected: str) -> float:
    return 1.0 if exact_match(output, expected) else 0.0

# Normalised exact match: case-insensitive, whitespace-collapsed
import re

def normalised_exact_match(output: str, expected: str) -> bool:
    def normalise(s: str) -> str:
        return re.sub(r'\s+', ' ', s.strip().lower())
    return normalise(output) == normalise(expected)

import json
import jsonschema

def validate_json_output(output: str, schema: dict) -> dict:
    """
    Check that output is valid JSON conforming to schema.
    Returns {valid: bool, errors: list[str]}.
    """
    try:
        data = json.loads(output)
    except json.JSONDecodeError as e:
        return {"valid": False, "errors": [f"JSON parse error: {e}"]}

    validator = jsonschema.Draft7Validator(schema)
    errors = [e.message for e in validator.iter_errors(data)]
    return {"valid": len(errors) == 0, "errors": errors}

